#pragma OPENCL EXTENSION cl_khr_fp64 : enable

#define ETA 0.3f
#define MOMENTUM 0.3f
#define BLOCK_SIZE 16
#define WIDTH 16
#define HEIGHT 16

__kernel void bpnn_layerforward_ocl(__global float* input_units,
                                   __global float* hidden_units,
                                   __global float* input_weights,
                                   __global float* hidden_partial_sum,
                                   __local float* lsum,
                                   __local float* linput,
                                   const int input_n,
                                   const int hidden_n)
{
    int tx = get_local_id(0);
    int ty = get_local_id(1);
    int bx = get_group_id(0);
    int by = get_group_id(1);

    int row = by * BLOCK_SIZE + ty; // input index
    int col = bx * BLOCK_SIZE + tx; // hidden index

    // Load input units into local memory
    if (row <= input_n && tx == 0) {
        linput[ty] = input_units[row];
    }
    barrier(CLK_LOCAL_MEM_FENCE);

    float sum = 0.0f;

    // Each work-item computes partial sum for one element
    if (row <= input_n && col <= hidden_n) {
        int idx = row * (hidden_n + 1) + col;
        sum = input_weights[idx] * linput[ty];
    }

    // Store partial sums in local memory
    lsum[ty * BLOCK_SIZE + tx] = sum;
    barrier(CLK_LOCAL_MEM_FENCE);

    // Reduction in local memory to sum over input_n dimension
    // sum over rows for each col
    if (ty == 0 && col <= hidden_n) {
        float local_sum = 0.0f;
        int limit = min(BLOCK_SIZE, input_n + 1);
        for (int i = 0; i < limit; i++) {
            local_sum += lsum[i * BLOCK_SIZE + tx];
        }
        int idx_out = col;
        hidden_partial_sum[by * BLOCK_SIZE + col] = local_sum;
    }
}

__kernel void bpnn_adjust_weights_ocl(__global float* delta,
                                     const int ndelta,
                                     __global float* ly,
                                     const int nly,
                                     __global float* w,
                                     __global float* oldw)
{
    int j = get_global_id(0) + 1; // from 1 to ndelta
    int k = get_global_id(1);     // from 0 to nly

    if (j <= ndelta && k <= nly) {
        int idx = k * (ndelta + 1) + j;
        float new_dw = ETA * delta[j] * ly[k] + MOMENTUM * oldw[idx];
        w[idx] += new_dw;
        oldw[idx] = new_dw;
    }
}
